import UIKit
import Foundation

class Stock {
    var symbol: String
    var price: Double
    
    init(symbol: String, price: Double) {
        self.symbol = symbol
        self.price = price
    }
}

class Portfolio {
    var holdings: [String: Int] = [:]
    
    func buy(stock: Stock, quantity: Int) {
        holdings[stock.symbol, default: 0] += quantity
    }
    
    func sell(stock: Stock, quantity: Int) {
        if let currentQuantity = holdings[stock.symbol], currentQuantity >= quantity {
            holdings[stock.symbol] = currentQuantity - quantity
        }
    }
}

class TradeService {
    let apiKey = "YOUR_API_KEY"
    let baseURL = "https://api.tradingplatform.com"
    
    func executeTrade(stock: Stock, quantity: Int, completion: @escaping (Bool) -> Void) {
        guard let url = URL(string: "\(baseURL)/executeTrade") else { return }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.addValue("application/json", forHTTPHeaderField: "Content-Type")
        request.addValue(apiKey, forHTTPHeaderField: "Authorization")
        
        let tradeDetails = ["symbol": stock.symbol, "quantity": quantity]
        request.httpBody = try? JSONSerialization.data(withJSONObject: tradeDetails)
        
        let task = URLSession.shared.dataTask(with: request) { data, response, error in
            guard error == nil else {
                completion(false)
                return
            }
            completion(true)
        }
        task.resume()
    }
}

class TradingViewController: UIViewController {
    var portfolio = Portfolio()
    var tradeService = TradeService()
    
    func buyStock(stock: Stock, quantity: Int) {
        portfolio.buy(stock: stock, quantity: quantity)
        tradeService.executeTrade(stock: stock, quantity: quantity) { success in
            if success {
                print("Trade executed successfully")
            } else {
                print("Trade execution failed")
            }
        }
    }
    
    func sellStock(stock: Stock, quantity: Int) {
        portfolio.sell(stock: stock, quantity: quantity)
        tradeService.executeTrade(stock: stock, quantity: -quantity) { success in
            if success {
                print("Trade executed successfully")
            } else {
                print("Trade execution failed")
            }
        }
    }
}

